class Solution:
    def maxSum(self, nums: List[int]) -> int:
        max_digits = {}
        for num in nums:
            max_d = max(int(d) for d in str(num))
            if max_d not in max_digits:
                max_digits[max_d] = []
            max_digits[max_d].append(num)

        result = -1
        for key in max_digits:
            if len(max_digits[key]) >= 2:
                current_sum = sum(max_digits[key])
                if current_sum > result:
                    result = current_sum
        return result
